    pass

solution:
def two_sum_sorted(a, target):
    a = sorted(a)
    i, j = 0, len(a) - 1
    while i < j:
        s = a[i] + a[j]
        if s == target:
            return (a[i], a[j])
        elif s < target:
            i += 1
        else:
            j -= 1
    return None

